class MagixTableSorter{constructor(){this.containers=document.querySelectorAll(".ui-sortable"),this.containers.length>0&&this.init()}init(){this.containers.forEach((e=>{const t=e.getAttribute("data-sort-url");new Sortable(e,{handle:".sort-handle",animation:150,ghostClass:"bg-light",dragClass:"shadow-lg",onEnd:async r=>{if(r.oldIndex===r.newIndex)return;const a=e.querySelectorAll("tr.sortable-row"),o=Array.from(a).map((e=>e.getAttribute("data-id")));await this.saveOrder(t,o)}})}))}async saveOrder(e,t){if(!e)return console.error("MagixTableSorter : URL de tri manquante sur le tbody."),void("undefined"!=typeof MagixToast&&MagixToast.error("Configuration du tri invalide."));try{const r=await fetch(e,{method:"POST",headers:{"Content-Type":"application/json","X-Requested-With":"XMLHttpRequest"},body:JSON.stringify({order:t})}),a=await r.json();a.success?("undefined"!=typeof MagixToast&&MagixToast.success(a.message||"L'ordre a été sauvegardé."),document.dispatchEvent(new CustomEvent("magix:sortSuccess",{detail:a}))):"undefined"!=typeof MagixToast&&MagixToast.error(a.message||"Erreur lors de la sauvegarde.")}catch(e){console.error("Erreur réseau / MagixTableSorter :",e),"undefined"!=typeof MagixToast&&MagixToast.error("Impossible de joindre le serveur.")}}}document.addEventListener("DOMContentLoaded",(()=>{"undefined"!=typeof Sortable?new MagixTableSorter:console.warn("MagixTableSorter requiert SortableJS. Le tri des tableaux est désactivé.")}));